using System.Collections.Generic;
using System.Reflection;
using UnityEngine;
using Cinemachine;

/// <summary>
/// CameraManager — bounds/blockers e confiner (Tarefa #21): calcula a
/// interseção entre a área base (<see cref="CameraAreaBounds"/>) e quaisquer
/// blockers activos (<see cref="CameraBlocker"/>), e escreve o resultado no
/// PolygonCollider2D usado pelo CinemachineConfiner2D das 3 vcams automáticas.
/// </summary>
public partial class CameraManager
{
    [Header("Confiner Runtime Bounds (FinalBounds PolygonCollider2D)")]
    [SerializeField] private PolygonCollider2D finalBoundsCollider;

    // Bounds (area) + blockers
    private BoxCollider2D baseBounds;
    private readonly List<BoxCollider2D> activeBlockerBounds = new();

    // Cache da reflexão: resolvida uma vez só (mesmo tipo p/ todas as vcams)
    private static MethodInfo confinerInvalidateMethod;
    private static bool confinerMethodResolved;

    public void SetBaseBounds(BoxCollider2D bounds)
    {
        if (baseBounds == bounds) return; // evita recalcular todo frame (OnTriggerStay2D)

        baseBounds = bounds;
        UpdateConfinerBounds();
    }

    public void AddBlocker(BoxCollider2D allowedBounds)
    {
        if (allowedBounds == null) return;
        if (!activeBlockerBounds.Contains(allowedBounds))
            activeBlockerBounds.Add(allowedBounds);

        UpdateConfinerBounds();
    }

    public void RemoveBlocker(BoxCollider2D allowedBounds)
    {
        if (allowedBounds == null) return;
        activeBlockerBounds.Remove(allowedBounds);
        UpdateConfinerBounds();
    }

    private void UpdateConfinerBounds()
    {
        if (finalBoundsCollider == null) return;
        if (baseBounds == null) return;

        Rect baseRect = GetWorldRect(baseBounds);
        Rect finalRect = baseRect;

        for (int i = 0; i < activeBlockerBounds.Count; i++)
        {
            var b = activeBlockerBounds[i];
            if (b == null) continue;

            Rect br = GetWorldRect(b);
            Rect inter = Intersect(finalRect, br);

            if (inter.width > 0.01f && inter.height > 0.01f)
                finalRect = inter;
        }

        finalBoundsCollider.pathCount = 1;

        Transform t = finalBoundsCollider.transform;

        Vector3 wp0 = new Vector3(finalRect.xMin, finalRect.yMin, 0f);
        Vector3 wp1 = new Vector3(finalRect.xMax, finalRect.yMin, 0f);
        Vector3 wp2 = new Vector3(finalRect.xMax, finalRect.yMax, 0f);
        Vector3 wp3 = new Vector3(finalRect.xMin, finalRect.yMax, 0f);

        Vector2 p0 = t.InverseTransformPoint(wp0);
        Vector2 p1 = t.InverseTransformPoint(wp1);
        Vector2 p2 = t.InverseTransformPoint(wp2);
        Vector2 p3 = t.InverseTransformPoint(wp3);

        finalBoundsCollider.SetPath(0, new Vector2[] { p0, p1, p2, p3 });

        InvalidateConfiner(vcamNormal);
        InvalidateConfiner(vcamCorridor);
        InvalidateConfiner(vcamBoss);
    }

    private void InvalidateConfiner(CinemachineVirtualCamera vcam)
    {
        if (vcam == null) return;
        var conf = vcam.GetComponent<CinemachineConfiner2D>();
        if (conf == null) return;

        if (!confinerMethodResolved)
        {
            // Compatível com várias versões (InvalidateCache / InvalidatePathCache)
            var t = conf.GetType();
            confinerInvalidateMethod = t.GetMethod("InvalidateCache", BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic)
                                     ?? t.GetMethod("InvalidatePathCache", BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
            confinerMethodResolved = true;
        }

        confinerInvalidateMethod?.Invoke(conf, null);
    }

    private static Rect GetWorldRect(BoxCollider2D col)
    {
        Bounds b = col.bounds;
        return new Rect(b.min.x, b.min.y, b.size.x, b.size.y);
    }

    private static Rect Intersect(Rect a, Rect b)
    {
        float xMin = Mathf.Max(a.xMin, b.xMin);
        float xMax = Mathf.Min(a.xMax, b.xMax);
        float yMin = Mathf.Max(a.yMin, b.yMin);
        float yMax = Mathf.Min(a.yMax, b.yMax);

        float w = xMax - xMin;
        float h = yMax - yMin;

        if (w <= 0f || h <= 0f) return new Rect(0, 0, 0, 0);
        return new Rect(xMin, yMin, w, h);
    }
}
